async (params, browser) => {
  // Search Yahoo Finance
  await browser.open(`https://finance.yahoo.com/lookup?s=${params.query}`)

  // Wait for search results
  await browser.waitForSelector('table tbody tr, [class*=\'lookup\'] table, [data-testid=\'table-container\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const rows = document.querySelectorAll('table tbody tr, [data-testid="table-container"] tbody tr'); for (let i = 0; i < Math.min(rows.length, 15); i++) { const row = rows[i]; const cells = row.querySelectorAll('td'); if (cells.length >= 2) { const symbolEl = cells[0] ? cells[0].querySelector('a') || cells[0] : null; const nameEl = cells[1]; const priceEl = cells.length > 2 ? cells[2] : null; const changeEl = cells.length > 3 ? cells[3] : null; const typeEl = cells.length > 4 ? cells[4] : null; const exchangeEl = cells.length > 5 ? cells[5] : null; results.push({ symbol: symbolEl ? symbolEl.textContent.trim() : '', name: nameEl ? nameEl.textContent.trim() : '', last_price: priceEl ? priceEl.textContent.trim() : '', change: changeEl ? changeEl.textContent.trim() : '', type: typeEl ? typeEl.textContent.trim() : '', exchange: exchangeEl ? exchangeEl.textContent.trim() : '', url: symbolEl && symbolEl.href ? symbolEl.href : '' }); } } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
